C["Iyyokuk selects: Drum |TInterface\\Icons\\ABILITY_IYYOKUK_DRUM_white.BLP:20|t!"]="Выбор Ийокука: барабан |TInterface\\Icons\\ABILITY_IYYOKUK_DRUM_white.BLP:20|t!"
